com.mirth.connect.plugins.javascriptstep.script:
var requestedPath = sourceMap.get('contextPath');
if (requestedPath == "/" || requestedPath == "/healthcheck") {
	return;
}

var mtlsEnabled = globalChannelMap.get('mtlsFilterEnabled');
if (String(mtlsEnabled) !== 'true') {
	logger.error('[RouterChannel] mTLS filter is disabled – rejecting request with 500');
	channelMap.put('mtlsFilterDisabled', 'true');
	destinationSet.removeAll();
	return;
}

var requestedPath = sourceMap.get('contextPath');
if (requestedPath == "/" ||  requestedPath ==  "/healthcheck") {
	return;
}

logger.info("Request URL inside RouterChannel: " + requestedPath);

var contentType = $('headers').getHeader('Content-Type');
channelMap.put("contentType", contentType);

if (requestedPath == "/Bundle/" || requestedPath == "/Bundle") {
	channelMap.put('destinationUrl', "http://localhost:9003" + requestedPath); 	
	logger.info("FHIRBundle submission  RouterChannel ");
}

else if (requestedPath == "/Bundle/$validate/" || requestedPath == "/Bundle/$validate") {
	channelMap.put('destinationUrl', "http://localhost:9001" + requestedPath);
	logger.info("FHIRBundle validation  RouterChannel ");
}


else if (requestedPath == "/ccda/Bundle/" || requestedPath == "/ccda/Bundle") {
	channelMap.put('destinationUrl', "http://localhost:9002" + requestedPath);	
	logger.info("CCDA submission  RouterChannel ");
}

else if (requestedPath == "/ccda/Bundle/$validate/" || requestedPath == "/ccda/Bundle/$validate") {
	channelMap.put('destinationUrl', "http://localhost:9002" + requestedPath);	
	logger.info("CCDA validation  RouterChannel ");
}


else if (requestedPath == "/flatfile/csv/Bundle/" || requestedPath == "/flatfile/csv/Bundle") {
	channelMap.put('destinationUrl', "http://localhost:9004" + requestedPath);
	logger.info("CSV FlatFile submission  RouterChannel ");
}

else if (requestedPath == "/flatfile/csv/Bundle/$validate/" || requestedPath == "/flatfile/csv/Bundle/$validate") {
	channelMap.put('destinationUrl', "http://localhost:9004" + requestedPath);
	logger.info("CSV FlatFile validation  RouterChannel ");
}

else if (requestedPath == "/hl7v2/Bundle/" || requestedPath == "/hl7v2/Bundle") {
	channelMap.put('destinationUrl', "http://localhost:9006" + requestedPath);	
	logger.info("HL7 submission  RouterChannel ");
}



else if (requestedPath == "/hl7v2/Bundle/$validate/" || requestedPath == "/hl7v2/Bundle/$validate") {
	channelMap.put('destinationUrl', "http://localhost:9006" + requestedPath);	
	logger.info("HL7 validation  RouterChannel ");
}
else{
	return;
}


var fhirJson  = connectorMessage.getRawData();
channelMap.put('fhirJson', fhirJson);
logger.info(fhirJson);

com.mirth.connect.plugins.javascriptrule.script:
var httpMethod = String(sourceMap.get('method')).toUpperCase();
var contextPath = String(connectorMessage.getSourceMap().get('contextPath')).replace(/\/$/, '');

// HEALTHCHECK
if (contextPath === '/healthcheck') {

	if (httpMethod === 'GET') {
		responseMap.put('responseStatusCode', 200);
		responseMap.put('responseContentType', 'application/json');
		responseMap.put('responseBody', JSON.stringify({
			status: 200,
			message: "OK"
		}));
	
		return false;
	}

	return methodNotAllowed();
}


// Helper Functions

function methodNotAllowed() {

	var errorResponse = "Method Not Allowed.";

	responseMap.put('responseStatusCode', 405);
	responseMap.put('responseContentType', 'application/json');
	responseMap.put('responseBody', JSON.stringify(errorResponse));

	setErrorResponse(405, errorResponse);

	throw "Invalid method";
}




// Signal that the mTLS filter rule is active (checked by source transformer)
globalChannelMap.put('mtlsFilterEnabled', true);

var remoteAddress = sourceMap.get('remoteAddress') || '';

var group1 = $('headers').getHeader('X-TechBD-Group-Interaction-ID');

var sourceType = $('headers').getHeader('X-TechBD-Source-Type');

if(sourceType == "CSV") { // TODO: Add a dedicated condition to handle the health check when the filter is enabled.
	return true;
} else {
	return performCertValidation("chain", "Util-sbx-bl-net.JKS", null);
}

com.mirth.connect.plugins.javascriptstep.script:
var requestedPath = sourceMap.get('contextPath');
if (requestedPath == "/" ||  requestedPath ==  "/healthcheck") {
  return;
}


// ======================================================
// PARSE HEADERS STRING + FORWARD
// ======================================================
var headersMap = new java.util.HashMap();
var headers = $('headers');
logger.info("HEADERS OBJECT: " + $('headers'));
if (headers != null) {
    var headerStr = String(headers);  // Convert full object to string
    // Remove { and }
    headerStr = headerStr.replace(/^\{|\}$/g, '');
    var pairs = headerStr.split(', ');
    for (var i = 0; i < pairs.length; i++) {
        var parts = pairs[i].split('=');
        if (parts.length === 2) {

            var key = parts[0].trim();
            var value = parts[1].trim();
            // Remove [ ]
            var headerValue = value.replace(/^\[|\]$/g, '');

            if (headerValue !== '' && key.toLowerCase() !== 'content-length') {
               // logger.info("INCOMING HEADER: " + key + " = " + headerValue);
                headersMap.put(key, headerValue);
            }
        }
    }
}
// Send headers via HTTP Sender
connectorMap.put("routerheaders", headersMap);



var paramsMap = new java.util.HashMap();
var inboundParams = $('parameters'); // Get query params from source

if (inboundParams != null) {
    var paramsStr = String(inboundParams);

    // Clean the { } brackets
    paramsStr = paramsStr.replace(/^\{|\}$/g, '');

    if (paramsStr.length > 0) {
        var pPairs = paramsStr.split(', ');
        for (var j = 0; j < pPairs.length; j++) {
            var pParts = pPairs[j].split('=');
            if (pParts.length === 2) {
                var pKey = pParts[0].trim();
                var pValue = pParts[1].trim();

                // Clean the [ ] brackets from the value
                var finalPValue = pValue.replace(/^\[|\]$/g, '');

                if (finalPValue !== '') {
                    paramsMap.put(pKey, finalPValue);
                }
            }
        }
    }
}

// Store for the HTTP Sender
connectorMap.put("routerparams", paramsMap);




// CRITICAL: REMOVE BODY COMPLETELY
return '';

channel.postprocessingScript:
//////////////////////////////////////////////////////
// This script executes once after a message has been processed

var requestedPath = sourceMap.get('contextPath');
if (requestedPath == "/" || requestedPath == "/healthcheck") {
    return;
}

// If mTLS filter is disabled, return 500 immediately
if (String(channelMap.get('mtlsFilterDisabled')) === 'true') {

    var mtlsErrorBody = JSON.stringify({
        resourceType: "OperationOutcome",
        issue: [{
            severity: "error",
            code: 500,
            diagnostics: "mTLS filter is disabled."
        }]
    });

    var mtlsResp = new com.mirth.connect.userutil.Response(
        com.mirth.connect.userutil.Status.ERROR,
        new java.lang.String(mtlsErrorBody)
    );
    responseMap.put('d1', mtlsResp);

    logger.error('PostProcessor: mTLS filter disabled – returning 500');
    return;
}

var destinationName = "response_operationoutcome";
var destinationResponse = responseMap.get(destinationName);

if (destinationResponse) {

    var responseStatus = String(destinationResponse.getStatus());

    // =========================
    // ERROR HANDLING BLOCK
    // =========================
    if (responseStatus === 'ERROR') {

        var responseError = '';
        try { responseError = String(destinationResponse.getError()); } catch (ex) {}

        var statusMessage = String(destinationResponse.getStatusMessage() || '');
        var responseData = destinationResponse.getMessage();

        // ✅ Keep RAW + lowercase versions
        var rawErrorDetail = responseError + ' ' + statusMessage + ' ' + String(responseData || '');
        var errorDetail = rawErrorDetail.toLowerCase();

        logger.error('PostProcessor ERROR detail: ' + rawErrorDetail);

        // ---- Detect conditions ----
        var isTimeout = errorDetail.indexOf('timeout') !== -1
                     || errorDetail.indexOf('timed out') !== -1
                     || errorDetail.indexOf('sockettimeoutexception') !== -1
                     || errorDetail.indexOf('read timed out') !== -1;

        var isConnRefused = errorDetail.indexOf('connection refused') !== -1
                         || errorDetail.indexOf('connectexception') !== -1;

        // ---- Extract downstream HTTP status ----
        var extractedStatus = null;

        try {
            var raw = String(responseData || '');
            var parsed = JSON.parse(raw);
            if (parsed && parsed.status != null) {
                extractedStatus = parseInt(parsed.status);
            }
        } catch (e) {
            // Fallback regex
            var statusMatch = errorDetail.match(/"status"\s*:\s*(\d{3})/);
            if (statusMatch) {
                extractedStatus = parseInt(statusMatch[1]);
            }
        }

        var statusNum = Number(extractedStatus);

        var statusCode, issueCode, diagnosticMsg;

        if (isTimeout) {
            statusCode = 504;
            issueCode = 'timeout';
            diagnosticMsg = 'The downstream service did not respond within the allowed time.';

        } else if (isConnRefused) {
            statusCode = 502;
            issueCode = 'exception';
            diagnosticMsg = 'Unable to connect to the downstream service.';

        } else if (!isNaN(statusNum) && statusNum >= 400) {
            // ✅ Respect downstream status
            statusCode = statusNum;
            issueCode = statusNum >= 500 ? 'exception' : 'processing';

            diagnosticMsg = 'Downstream error (' + statusNum + '): ' + rawErrorDetail.substring(0, 1000);

        } else {
            // Fallback
            statusCode = 502;
            issueCode = 'exception';
            diagnosticMsg = 'Unknown downstream error. Detail: ' + rawErrorDetail.substring(0, 1000);
        }

        // ---- Build OperationOutcome ----
        var operationOutcome = JSON.stringify({
            resourceType: "OperationOutcome",
            issue: [{
                severity: "error",
                code: issueCode,
                diagnostics: diagnosticMsg
            }]
        });

        // ✅ Modify response in-place (critical)
        destinationResponse.setMessage(new java.lang.String(operationOutcome));
        destinationResponse.setStatus(com.mirth.connect.userutil.Status.SENT);
        destinationResponse.setStatusMessage('Error handled in PostProcessor');

        channelMap.put('status', String(statusCode));

        logger.error('PostProcessor: Final status=' + statusCode + ', body length=' + operationOutcome.length);

        return;
    }

    // =========================
    // SUCCESS FLOW
    // =========================

    // Default success
    channelMap.put('status', '200');

    try {
        var jsonStr = String(destinationResponse.getMessage());
        var jsonResponse = JSON.parse(jsonStr);

        var bodyStatus = jsonResponse["status"];

        if (bodyStatus != null && bodyStatus !== "") {
            channelMap.put('status', String(bodyStatus));
        }

    } catch (e) {
        logger.warn("PostProcessor: JSON parse failed: " + e);
    }

} else {

    logger.error("PostProcessor: No response from destination: " + destinationName);

    var noResponseOutcome = JSON.stringify({
        resourceType: "OperationOutcome",
        issue: [{
            severity: "error",
            code: "exception",
            diagnostics: "No response received from downstream service."
        }]
    });

    var newResp = new com.mirth.connect.userutil.Response(
        com.mirth.connect.userutil.Status.SENT,
        new java.lang.String(noResponseOutcome)
    );

    responseMap.put(destinationName, newResp);
    channelMap.put('status', '502');
}

return;

channel.deployScript:
// This script executes once when the channel is deployed
// You only have access to the globalMap and globalChannelMap here to persist data


// Flag starts as false; the mTLS filter rule will set it to true when it executes.
globalChannelMap.put('mtlsFilterEnabled', false);

return;

channel.undeployScript:
// This script executes once when the channel is undeployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;
